import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.filter.js";
import "core-js/modules/es.iterator.find.js";
import "core-js/modules/es.iterator.for-each.js";
import "core-js/modules/es.iterator.map.js";
import { mapState } from "vuex";
import CustomSelect from "../components/CustomSelect.vue";
import AllyPlayer from "../components/ChampSelect/AllyPlayer.vue";
import EnemyPlayer from "../components/ChampSelect/EnemyPlayer.vue";
import Champion from "../components/ChampSelect/Champion.vue";
import Skin from "../components/ChampSelect/Skin.vue";
import ChampionBan from "../components/ChampSelect/ChampionBan.vue";
import RuneMasteryEditor from "../components/RuneMasteryEditor.vue";
export default {
  components: {
    AllyPlayer,
    EnemyPlayer,
    Champion,
    Skin,
    ChampionBan,
    CustomSelect,
    RuneMasteryEditor
  },
  mounted() {
    this.$sound.template("CHAMPSELECT_INTRO");
    this.$store.dispatch("loadRuneMasteryPages");
    setTimeout(() => {
      if (this.champselect.lobbyType === "SUMMONERS_RIFT_DRAFT") {
        this.audioId = this.$sound.template("CHAMPSELECT_MUSIC_DRAFT");
      } else {
        this.audioId = this.$sound.template("CHAMPSELECT_MUSIC_BLIND");
      }
    }, 1750);
  },
  data() {
    return {
      skins: [],
      skinCarouselPosition: 1,
      stateTimer: null,
      stateTime: 0,
      selectedTab: "CHAMPIONS",
      selectableSpells: 1,
      selectedSpells: 0,
      selectingSpell: null,
      lastState: "",
      wasTrading: false,
      lastMessages: null,
      audioId: null,
      showRuneMasteryEditor: false
    };
  },
  created() {
    this.$store.dispatch("getCollectionChampions").then(champions => {
      for (let champion in champions) {
        new Audio(this.$sound.getPath({
          type: "SOUND",
          state: "CHAMPSELECT_GENERAL",
          fileName: "champions/" + champions[champion].id + ".mp3"
        }));
      }
    });
  },
  methods: {
    getCarouselStyle() {
      return `--position:${this.skinCarouselPosition};`;
    },
    nextSkin() {
      if (this.skinCarouselPosition != this.skins.length) {
        this.skinCarouselPosition += 1;
        this.selectSkin(this.skins[this.skinCarouselPosition - 1]);
      }
    },
    previousSkin() {
      if (this.skinCarouselPosition != 1) {
        this.skinCarouselPosition -= 1;
        this.selectSkin(this.skins[this.skinCarouselPosition - 1]);
      }
    },
    selectSkin(skin) {
      if (!skin.owned) return;
      this.$socket.sendChampSelectMessage("CHAMPSELECT_SELECT_SKIN", {
        data: skin.name
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        this.$sound.template("CHAMPION_GRID_CLICK");
        console.log("SELECTED SKIN " + skin.name + " FROM CHAMPION " + skin.championId);
      });
    },
    showSpellModal(both, spellid = null) {
      if (both) {
        this.selectableSpells = 2;
      } else {
        this.selectableSpells = 1;
        this.selectingSpell = spellid;
      }
      this.selectedSpells = 0;
      if (!this.$refs.spellmodal.classList.contains("visible")) {
        this.$refs.spellmodal.classList.add("visible");
      } else {
        this.$refs.spellmodal.classList.remove("visible");
      }
    },
    selectSpell(spell) {
      if (this.selectableSpells == 2) {
        if (this.selectedSpells === 0) {
          // Selecting first spell, always spellid 1
          this.$socket.sendChampSelectMessage("CHAMPSELECT_SELECT_SPELL_1", {
            data: this.convertSpell(spell)
          }, (response, error) => {
            if (error) {
              console.log("Flyback error:");
              console.log(error);
            }
            this.selectedSpells = 1;
            console.log("Changed spell 1 to " + spell);
          });
        } else {
          // Selecting second spell should close modal, always spellid 2
          this.$socket.sendChampSelectMessage("CHAMPSELECT_SELECT_SPELL_2", {
            data: this.convertSpell(spell)
          }, (response, error) => {
            if (error) {
              console.log("Flyback error:");
              console.log(error);
            }
            this.selectedSpells = 2;
            console.log("Changed spell 2 to" + spell);
            this.$refs.spellmodal.classList.remove("visible");
          });
        }
      } else {
        // Selected spell should close now, spellid is selectingspell
        this.$refs.spellmodal.classList.remove("visible");
        this.$socket.sendChampSelectMessage(`CHAMPSELECT_SELECT_SPELL_${this.selectingSpell}`, {
          data: this.convertSpell(spell)
        }, (response, error) => {
          if (error) {
            console.log("Flyback error:");
            console.log(error);
          }
          console.log("Changed spell " + this.selectingSpell + " to " + spell);
          this.$refs.spellmodal.classList.remove("visible");
        });
      }
    },
    convertSpell(spell, fromenum = false) {
      if (fromenum) {
        spell = spell.toLowerCase();
        const parts = spell.split("_");
        parts.forEach((part, index) => {
          parts[index] = part.charAt(0).toUpperCase() + part.slice(1);
        });
        return parts.join("");
      } else {
        const parts = spell.match(/[A-z][a-z]+/g);
        parts.forEach((part, index) => {
          parts[index] = part.toUpperCase();
        });
        return parts.join("_");
      }
    },
    selectedRunePage() {
      console.log("RUNEPAGE SELECTED");
    },
    selectedMasteryPage() {
      console.log("RUNEPAGE SELECTED");
    },
    onRunePageSelected(option) {
      const index = this.runePageOptions.indexOf(option);
      if (index >= 0) {
        this.$store.dispatch("selectRunePage", index);
      }
    },
    onMasteryPageSelected(option) {
      const index = this.masteryPageOptions.indexOf(option);
      if (index >= 0) {
        this.$store.dispatch("selectMasteryPage", index);
      }
    },
    editRuneMastery() {
      this.showRuneMasteryEditor = true;
    },
    closeRuneMasteryEditor() {
      this.showRuneMasteryEditor = false;
    },
    lockedInChampion() {
      if (this.currentPlayer && !this.currentPlayer.selectedChampion) return;
      this.$socket.sendChampSelectMessage("CHAMPSELECT_LOCK_CHAMPION", {
        data: this.currentPlayer.selectedChampion.id
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        this.$sound.template("LOCKIN_CLICK");
        console.log("LOCKED IN CHAMPION " + this.currentPlayer.selectedChampion.id);
        this.skins = this.getSkins(this.currentPlayer.selectedChampion.id);
        this.selectedTab = "SKINS";
        this.$sound.play({
          type: "SOUND",
          state: "CHAMPSELECT_GENERAL",
          fileName: "champions/" + this.currentPlayer.selectedChampion.id + ".mp3"
        });
      });
    },
    lockedInBan() {
      if (this.currentPlayer && !this.currentPlayer.selectedChampion) return;
      const bannedChampId = this.currentPlayer.selectedChampion.id;
      this.$socket.sendChampSelectMessage("CHAMPSELECT_BAN_LOCK_CHAMPION", {
        data: this.currentPlayer.selectedChampion.id
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        this.$sound.template("LOCKIN_CLICK");
        console.log("BANNED CHAMPION " + bannedChampId);
      });
    },
    getSpell(spellid, spell = null) {
      const {
        host,
        port
      } = this.$store.state.config.download;
      if (spellid === false) {
        return `${host}:${port}/summoner_spells/${spell}.jpg`;
      }
      let spells = ["SummonerHeal", "SummonerFlash"];
      if (this.currentPlayer.spell1) {
        spells = [this.convertSpell(this.currentPlayer.spell1, true), this.convertSpell(this.currentPlayer.spell2, true)];
      }
      return `${host}:${port}/summoner_spells/${spells[spellid]}.jpg`;
    },
    getSkins(championId) {
      let tempSkinsOwned = this.champions.find(c => c.id === championId).skins.owned;
      let tempSkinsNotOwned = this.champions.find(c => c.id === championId).skins.notOwned;
      tempSkinsOwned.forEach(e => {
        e.championId = championId;
        e.owned = true;
      });
      tempSkinsNotOwned.forEach(e => {
        e.championId = championId;
        e.owned = false;
      });
      return tempSkinsOwned.concat(tempSkinsNotOwned);
    },
    sendChatMessage() {
      const input = this.$refs.chatInput;
      const message = input.value;
      if (message.trim() == "") return;
      input.value = "";
      this.$socket.sendChampSelectMessage("CHAMPSELECT_CHAT", {
        data: message
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        this.$refs.chatMessages.scrollTop = this.$refs.chatMessages.scrollHeight;
      });
    },
    getTeamState(name) {
      if (!this.currentPlayer) return "UNDEFINED";
      const allyteam = this.currentPlayer.team;
      if (name == "ALLY") {
        switch (this.globalState.phase) {
          case "PICK":
            if (this.globalState.team == "BLIND" && !this.didFullyLock("ALLY")) {
              return "PICKING";
            } else if (this.globalState.team != "BLIND" && this.globalState.team == allyteam) {
              return "PICKING";
            } else {
              return "";
            }
          case "BAN":
            if (this.globalState.team == allyteam) {
              return "BANNING";
            } else {
              return "";
            }
          default:
            return "";
        }
      } else {
        switch (this.globalState.phase) {
          case "PICK":
            if (this.globalState.team == "BLIND" && !this.didFullyLock("ENEMY")) {
              return "PICKING";
            } else if (this.globalState.team != "BLIND" && this.globalState.team != allyteam) {
              return "PICKING";
            } else {
              return "";
            }
          case "BAN":
            if (this.globalState.team != allyteam) {
              return "BANNING";
            } else {
              return "";
            }
          default:
            return "";
        }
      }
    },
    didFullyLock(name) {
      if (name == "ALLY") {
        return this.champselect.team.filter(player => {
          return !player.lockedIn;
        }).length == 0;
      } else {
        return this.enemyTeam.filter(player => {
          return !player.lockedIn;
        }).length == 0;
      }
    },
    getGlobalStateMessage() {
      if (this.globalState.team == "BLIND") {
        switch (this.globalState.phase) {
          case "PICK":
            if (this.currentPlayer.canLockIn) {
              return this.$translate.text("CS_GLOBAL_STATE_PICK_SELF");
            } else if (!this.didFullyLock("ALLY")) {
              return this.$translate.text("CS_GLOBAL_STATE_PICK_ALLY");
            } else {
              return this.$translate.text("CS_GLOBAL_STATE_PICK_ENEMY");
            }
          case "PRE":
            return this.$translate.textWithParams("CS_GLOBAL_STATE_GAME_START", {
              stateTime: this.stateTime
            });
          default:
            return this.$translate.textWithParams("CS_GLOBAL_STATE_GAME_START", {
              stateTime: this.stateTime
            });
        }
      } else {
        switch (this.globalState.phase) {
          case "PICK":
            if (this.currentPlayer.canLockIn) {
              return this.$translate.text("CS_GLOBAL_STATE_PICK_SELF");
            } else if (this.currentPlayer.team == this.globalState.team) {
              return this.$translate.text("CS_GLOBAL_STATE_PICK_ALLY");
            } else {
              return this.$translate.text("CS_GLOBAL_STATE_PICK_ENEMY");
            }
          case "BAN":
            if (this.currentPlayer.canBan) {
              return this.$translate.text("CS_GLOBAL_STATE_BAN_SELF");
            } else if (this.currentPlayer.team == this.globalState.team) {
              return this.$translate.text("CS_GLOBAL_STATE_BAN_ALLY");
            } else {
              return this.$translate.text("CS_GLOBAL_STATE_BAN_ENEMY");
            }
          case "PRE":
            return this.$translate.textWithParams("CS_GLOBAL_STATE_GAME_START", {
              stateTime: this.stateTime
            });
          default:
            return this.$translate.textWithParams("CS_GLOBAL_STATE_GAME_START", {
              stateTime: this.stateTime
            });
        }
      }
    },
    typeAction() {
      this.$store.dispatch("searchFilterChampions", this.$refs.actionInput.value);
    }
  },
  computed: {
    runePageOptions() {
      if (this.runePages && this.runePages.length > 0) {
        return this.runePages.map(p => p.name);
      }
      return [this.t("CS_RUNEPAGE_1"), this.t("CS_RUNEPAGE_2"), this.t("CS_RUNEPAGE_3")];
    },
    masteryPageOptions() {
      if (this.masteryPages && this.masteryPages.length > 0) {
        return this.masteryPages.map(p => p.name);
      }
      return [this.t("CS_MASTERYPAGE_1"), this.t("CS_MASTERYPAGE_2"), this.t("CS_MASTERYPAGE_3")];
    },
    ...mapState({
      champions: state => state.collection.champions,
      chatMessages: state => state.champselectMessages,
      champselect: state => state.champselect,
      enemyTeam: state => state.csEnemyTeam,
      allyBans: state => state.csAllyBans,
      enemyBans: state => state.csEnemyBans,
      globalState: state => state.csGlobalState,
      currentPlayer: state => state.csCurrentPlayer,
      runePages: state => state.runePages,
      masteryPages: state => state.masteryPages,
      currentRunePage: state => state.currentRunePage,
      currentMasteryPage: state => state.currentMasteryPage,
      isTradingTarget: state => {
        if (state.champselect == {}) return false;
        const myTrades = state.champselect.tradesTeam.filter(trade => {
          return trade.target.user.summonerName == state.csCurrentPlayer.user.summonerName;
        });
        if (myTrades.length == 0) {
          return false;
        } else {
          return true;
        }
      },
      isTrading: state => {
        if (state.champselect == {}) return false;
        const myTrades = state.champselect.tradesTeam.filter(trade => {
          return trade.initiator.user.summonerName == state.csCurrentPlayer.user.summonerName || trade.target.user.summonerName == state.csCurrentPlayer.user.summonerName;
        });
        if (myTrades.length == 0) {
          return false;
        } else {
          return true;
        }
      },
      filteredChampions: state => {
        return state.collection.champions.filter(c => c.shouldShow);
      },
      filteredSpells: state => {
        return state.availableSpells.filter(c => {
          if (state.champselect.lobbyType == "ARAM_BLIND") {
            if (c === "SummonerOdinGarrison" || c === "SummonerClairvoyance" || c === "SummonerTeleport" || c === "SummonerSmite") {
              return false;
            }
          } else {
            if (c === "SummonerOdinGarrison") {
              return false;
            }
          }
          return true;
        });
      }
    })
  },
  updated() {
    if (this.wasTrading && !this.isTrading) {
      this.wasTrading = false;
      if (this.skins[0].championId != this.currentPlayer.selectedChampion.id) {
        this.skins = this.getSkins(this.currentPlayer.selectedChampion.id);
        this.skinCarouselPosition = 1;
      }
    } else if (!this.wasTrading && this.isTradingTarget) {
      this.$sound.template("CHAMPSELECT_TRADE");
      this.wasTrading = true;
    } else if (!this.wasTrading && this.isTrading) {
      this.wasTrading = true;
    }
    if (this.champselect.lobbyType == "ARAM_BLIND" && !this.skins.length) {
      this.skins = this.getSkins(this.currentPlayer.selectedChampion.id);
      this.skinCarouselPosition = 1;
      this.selectedTab = "SKINS";
    }
    if (this.lastMessages !== this.chatMessages.length) {
      this.lastMessages = this.chatMessages.length;
      this.$refs.chatMessages.scrollTop = this.$refs.chatMessages.scrollHeight;
    }
    if (this.lastState == "") {
      this.lastState = this.globalState ?? "NOT DEFAULT";
      this.stateTime = this.globalState.time;
      if (this.currentPlayer.canLockIn && !this.currentPlayer.lockedIn) {
        this.$sound.template("CHAMPSELECT_YOURTURN");
      }
      this.stateTimer = setInterval(() => {
        if (this.stateTime <= 0) {
          clearInterval(this.stateTimer);
        } else {
          this.stateTime--;
        }
      }, 1000);
    } else if (this.lastState.team != this.globalState.team || this.lastState.time != this.globalState.time || this.lastState.phase == this.globalState.phase && this.champselect.enemyTeam.length == 0 && (this.lastState.bannedChampionsLength != this.globalState.bannedChampionsLength || this.lastState.pickedChampionsLength != this.globalState.pickedChampionsLength) // Kill me :) -> We're depending on different time's for the phases here.
    ) {
      clearInterval(this.stateTimer);
      if (this.lastState.phase != this.globalState.phase) {
        this.$sound.template("CHAMPSELECT_PHASECHANGE");
      }
      if (this.currentPlayer.canLockIn && !this.currentPlayer.lockedIn) {
        this.$sound.template("CHAMPSELECT_YOURTURN");
      }
      this.lastState = this.globalState;
      this.stateTime = this.globalState.time;
      this.stateTimer = setInterval(() => {
        if (this.stateTime == 1) {
          this.$sound.template("CHAMPSELECT_EXIT");
        } else if (this.stateTime == 11) {
          this.$sound.template("CHAMPSELECT_COUNTDOWN");
        }
        if (this.stateTime <= 0) {
          clearInterval(this.stateTimer);
        } else {
          this.stateTime--;
        }
      }, 1000);
    }
  },
  beforeMount() {
    this.$store.dispatch("changeBackgroundState", "CHAMPSELECT");
  },
  beforeDestroy() {
    this.$sound.stopAll("CHAMPSELECT");
    clearInterval(this.stateTimer);
  }
};
